        private async Task<ValidationResult> ValidateFile(IFormFile file, HashSet<string> allowedExtensions, long maxSize)
        {
            if (file.Length > maxSize)
            {
                return new ValidationResult { IsValid = false, ErrorMessage = "File size exceeds maximum allowed" };
            }

            var extension = Path.GetExtension(file.FileName).ToLowerInvariant();
            
            if (string.IsNullOrEmpty(extension))
            {
                return new ValidationResult { IsValid = false, ErrorMessage = "File must have an extension" };
            }

            if (!allowedExtensions.Contains(extension))
            {
                return new ValidationResult { IsValid = false, ErrorMessage = $"File type {extension} is not allowed" };
            }

            var fileName = Path.GetFileName(file.FileName);
            if (fileName.IndexOfAny(Path.GetInvalidFileNameChars()) >= 0)
            {
                return new ValidationResult { IsValid = false, ErrorMessage = "File name contains invalid characters" };
            }

            if (fileName.Contains("..") || fileName.Contains("/") || fileName.Contains("\\"))
            {
                return new ValidationResult { IsValid = false, ErrorMessage = "File name contains invalid path characters" };
            }

            var isValidSignature = await ValidateFileSignature(file, extension);
            if (!isValidSignature)
            {
                return new ValidationResult { IsValid = false, ErrorMessage = "File content does not match its extension" };
            }

            return new ValidationResult { IsValid = true };
        }

        private async Task<bool> ValidateFileSignature(IFormFile file, string extension)
        {
            if (!AllowedFileSignatures.ContainsKey(extension))
            {
                return false;
            }

            var signatures = AllowedFileSignatures[extension];
            var maxSignatureLength = signatures.Max(s => s.Length);
            
            using (var reader = new BinaryReader(file.OpenReadStream()))
            {
                var headerBytes = reader.ReadBytes(maxSignatureLength);
                
                return signatures.Any(signature => 
                    headerBytes.Take(signature.Length).SequenceEqual(signature));
            }
        }

        private async Task<UploadResult> SaveFile(IFormFile file, string subDirectory)
        {
            var uploadDirectory = Path.Combine(_uploadBasePath, subDirectory);
            
