            var extension = Path.GetExtension(file.FileName).ToLowerInvariant();
            var safeFileName = GenerateSafeFileName(extension);
            var filePath = Path.Combine(uploadDirectory, safeFileName);

            var fullPath = Path.GetFullPath(filePath);
            var fullUploadDirectory = Path.GetFullPath(uploadDirectory);
            
            if (!fullPath.StartsWith(fullUploadDirectory, StringComparison.OrdinalIgnoreCase))
            {
